const e={name:"Brysselkål",icon:"brysselkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Brysselkål kräver tålamod - hon tar sin tid (120-180 dagar!) och vill ha näringsrik jord, stadigt stöd och jämn fukt. Men ger du henne det belönar hon dig med de godaste små kålhuvudena du kan tänka dig, särskilt efter första frosten.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"120-180",spacing:"50-60 cm",rowSpacing:"60-70 cm",depth:"1 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. I halvskugga blir skotten lösa och små - brysselkål vill ha ordentligt med ljus för att bygga täta, fina små huvuden längs stammen."},temperature:{min:-10,max:25,ideal:"15-18°C",detail:"Brysselkål är en riktig nordbo som trivs bäst i svalka, runt 15-18°C. Hon är extremt frosttålig - ner till -10°C! - och smaken blir faktiskt BÄTTRE efter frost. Över 25°C stressar hon och skotten blir lösa och bittra."},wind:{level:"Skyddat",detail:"Brysselkål blir en hög planta (60-90 cm) med tung last av skott längs stammen. Ge henne vindskydd eller en stödkäpp så hon inte blåser omkull när höststormarna drar in."}},watering:{need:"Medel-Hög",icon:"water",summary:"Brysselkål vill ha jämn fukt hela den långa säsongen. Ojämn vattning ger lösa, dåliga skott - och det vill vi inte efter månader av väntan.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Tryck till jorden ordentligt runt stammen - hon ska stå stadigt!"},{phase:"Tillväxt och stambildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon den långa stammen och alla bladveck där skotten ska bildas."},{phase:"Skottbildning (sensommar-höst)",need:"Hög",tip:"Kritisk period! Jämn fukt nu avgör om skotten blir täta och fina. Sluta inte vattna bara för att hösten kommer - hon behöver det ända till skörd."}],mistakes:["Ojämn vattning - torka följt av storvattning ger lösa, dåliga skott. Brysselkål vill ha jämn fukt hela vägen.","Ge upp vattningen på hösten - hon bildar skott ända in i november och behöver fukt hela tiden","Vattna ovanifrån sent på kvällen - fuktiga blad i mörkret bjuder in svampsjukdomar","Tro att hon klarar sig själv bara för att hon ser stor och tålig ut - speciellt under skottbildningen är hon känslig"],tip:"Mulcha ordentligt med gräsklipp eller halm runt stambasen. Det håller jorden fuktig och sval under den långa odlingssäsongen, och minskar ogräset som annars tar näring från din hungriga brysselkål."},soil:"Näringsrik, kalkrik, fast jord. Brysselkål vill ha stadigt fäste - inte för lös jord! Hon blir hög och tung, så jorden måste hålla henne på plats.",soilTips:["Kalka på hösten om pH är under 6.5 - brysselkål ÄLSKAR kalkrik jord och det skyddar mot klumprotsjuka","Blanda in rikligt med brunnen kompost och gärna hönsgödsel. Brysselkål är en storätare som ska växa i 5-6 månader.","Undvik för lös, nygrävd jord - hon behöver fast mark att stå i. Trampa gärna till lite runt plantan efter utplantering."],timeline:{1:[{phase:"Förodla inomhus",months:"Mar",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jul",icon:"water"},{phase:"Toppa plantan",months:"Aug-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Toppa plantan",months:"Sep",icon:"leaf"},{phase:"Skörd",months:"Okt-Dec",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Aug",icon:"water"},{phase:"Toppa plantan",months:"Sep-Okt",icon:"leaf"},{phase:"Skörd",months:"Okt-Dec",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:10,label:"Förodling"},{month:"Apr",N:25,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:55,P:25,K:20,label:"Utplantering"},{month:"Jun",N:75,P:35,K:25,label:"Stamtillväxt"},{month:"Jul",N:85,P:40,K:35,label:"Kraftig tillväxt"},{month:"Aug",N:70,P:35,K:45,label:"Skottbildning startar"},{month:"Sep",N:50,P:30,K:50,label:"Skotten mognar"},{month:"Okt",N:25,P:20,K:40,label:"Skörd nedifrån"},{month:"Nov",N:10,P:10,K:25,label:"Sista skörden"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Brysselkål ska växa i 5-6 månader och behöver en kväverik start för att bygga en kraftig stam."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Nu ska hon börja bygga höjd och bladmassa på allvar."},{timing:"Midsommar",tip:"En extra giva med allroundgödsel. Nu ökar tempot och hon behöver bränsle för alla de små skott som snart ska bildas i bladvecken."},{timing:"Sensommar (skottbildning)",tip:"Extra kalium (vedaska eller alggödsel) stärker skotten och förbättrar smaken. Minska kvävet nu - för mycket kväve ger lösa skott."}],companions:{good:[{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar brysselkålen för kålfjärilen. De trivs bra ihop och kompletterar varandra fint."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som brysselkålens personliga livvakt."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen. Ett klassiskt och beprövat kompanjonskap."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs verkligen inte ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd med den dealen."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte brysselkål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"vitkal",name:"Vitkål"},{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"rodkal",name:"Rödkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 6 år innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga brysselkål! Perfekt förfrukt.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som brysselkålen lämnar efter sig."},varieties:[{name:"Groninger",zones:[1,2,3,4,5],note:"Klassisk OP-sort med pålitlig skörd och fin smak. Blir gärna 70-80 cm hög med jämna, fasta skott. Ekofrö hos Runåbergs."},{name:"Long Island",zones:[1,2,3,4,5],note:"Kompakt OP-kultursort från 1890. Passar bra i mindre trädgårdar med tätt sittande skott. Finns hos Impecta."},{name:"Rubine",zones:[1,2,3,4],note:"Vacker röd/lila OP-kultursort som ger färg på tallriken. Unik smak och hög i antocyaniner. Kan stå ute hela vintern under snötäcke. Runåbergs."},{name:"Igor F1",zones:[1,2,3,4,5],note:"F1-hybrid med mycket jämna skott och god sjukdomsresistens. Bra val i tuffa zoner där du behöver lite extra säkerhet. Finns hos Nelson Garden. OBS: F1 - ger inte äkta avkomma vid frötagning."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar hål i bladen. Lämnar gröna spillningshögar och kan förstöra bladverket som plantan behöver för att bygga skott.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet. Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök för att förvirra fjärilarna."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Kålodlarens mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6 år. Svampen överlever i jorden extremt länge."},{name:"Lösa skott",symptom:"Skotten blir lösa och bladiga istället för täta och fasta. Ser ut som små öppna rosor istället för miniatyrkålhuvuden.",fix:"Oftast orsakat av för hög värme eller för lite ljus. Se till att plantan står i full sol. Toppa plantan (knip av toppen) i september - det tvingar energin ner i skotten. Minska kväve och öka kalium under skottbildningen."},{name:"Kålmal och jordloppor",symptom:"Kålmalen gör små hål i bladen, jordloppor gnager runda hål i unga plantor. Värst i varmt, torrt väder.",fix:"Fiberduk är bästa skyddet. Håll jorden fuktig - jordloppor avskyr fukt. Pudra med stenmjöl eller vedaska. Starka, välgödda plantor klarar angrepp bättre."}],goodToKnow:[{icon:"harvest",title:"Frost gör henne GODARE",text:"Brysselkål är extremt frosttålig (ner till -10°C!) och smaken blir faktiskt fantastiskt mycket bättre efter frost. Stärkelseinnehållet omvandlas till socker i kylan. Vänta med skörden till efter första frostnatten - du kommer inte ångra det.",severity:"tip"},{icon:"leaf",title:"Skörda nedifrån och uppåt",text:"Skotten mognar nedifrån och uppåt längs stammen. Börja skörda de nedersta när de är 2-3 cm i diameter och fasta. Bryt av bladen under skotten du skördar - det ger de övre skotten mer ljus och energi.",severity:"tip"},{icon:"seedling",title:"Toppa plantan i september",text:"Knip av toppskottet i september (zon 1-4) eller oktober (zon 5-6). Det stoppar höjdtillväxten och tvingar all energi ner i skotten som redan bildats. Ett avgörande trick för täta, fina skott.",severity:"tip"},{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kålväxter är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 6+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"warning",title:"Fiberduk hela säsongen",text:"Kålfjärilen flyger från maj till september. Lägg fiberduk vid utplantering och ta inte bort den förrän du skördar. Brysselkålens långa säsong gör henne extra utsatt.",severity:"warning"},{icon:"warning",title:"Stöd höga plantor",text:"Brysselkål kan bli 60-90 cm hög med en tung last av skott. Sätt en stödkäpp vid plantering eller kupa jord runt stambasen. En planta som blåser omkull i oktober efter 5 månaders väntan - det vill du undvika.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Brysselkål förodlas alltid inomhus - den långa säsongen (120-180 dagar) kräver tidig start. Så i mars-april beroende på zon. Direktsådd fungerar inte i Sverige - säsongen räcker helt enkelt inte till.",steps:["Så 1-2 cm djupt i krukor eller celler, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 50-60 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ORDENTLIGT runt stammen - hon ska stå stadigt i 5-6 månader. Vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Brysselkål behöver tidig start - förodla redan i mars (zon 1-3) eller april (zon 4-6) för att hinna mogna","Stram, kompakt planta vid utplantering är viktigare än stor planta - ge starkt ljus under förodlingen","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Brysselkål är tvåårig och sätter frö först andra året. Hela plantan med stam och skott måste övervintras och planteras ut igen. En rejäl utmaning - men för den som vill bevara sorter som Groninger är det värt mödan.",steps:["Välj den finaste, friskaste plantan med täta, jämna skott","Gräv upp hela plantan med roten på senhösten","Förvara svalt (0-5°C) över vintern - jordkällare eller ouppvärmt garage","Plantera ut igen på våren med intakt rot och stam","Skotten spricker upp och blomstjälkar växer ut ur dem","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, rödkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av brysselkål är bland de svåraste - du måste förvara en hel planta (60-90 cm!) över vintern. Men för OP-sorter som Groninger och Rubine är det enda sättet att bevara dem. F1-hybrider som Igor ger inte äkta avkomma."},storage:{shelfLife:"3-4 veckor (på stammen i kylskåp), 8-12 månader (fryst)",methods:[{method:"På stammen (bäst!)",icon:"storage",duration:"3-4 veckor",description:"Klipp av hela stammen och ställ i kylskåp. Skotten håller sig mycket längre på stammen än lösa. Gammalt knep som fungerar fantastiskt.",best:!0},{method:"Kylskåp (lösa)",icon:"snowflake",duration:"1-2 veckor",description:"Lösa skott i plastpåse med några hål i grönsakslådan. Håller sämre än på stammen men funkar för kortare lagring.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Halvera stora skott, blanchera 3-4 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för grytor, gratänger och wok. Texturen mjuknar men smaken består fint.",best:!1},{method:"Stående i trädgården",icon:"storage",duration:"Till -10°C",description:'Brysselkål tål rejäl frost. Låt henne stå kvar i trädgården och skörda efter behov. Det bästa "lagret" som finns - levande färskvaruförråd rakt ut genom dörren!',best:!1}],tips:["Låt brysselkålen stå kvar i trädgården så länge det går - hon tål frost ner till -10°C och smaken bara blir bättre","Skörda hela stammen och ställ i ett kallt garage eller jordkällare - skotten håller sig i veckor","Frysta brysselkål är utmärkt i grytor och gratänger - blanchera alltid före frysning","Skörda nedifrån och uppåt - ta de nedersta skotten först så får de övre mer tid att växa till sig","Små, täta skott håller bättre och smakar godare än stora, lösa. Skörda när de är 2-3 cm i diameter."]},harvestCalc:{minPerSqm:.8,maxPerSqm:1.5,unit:"kg"}};export{e as brysselkal};
